export interface EditorSuccessCriterion { id: string; category: string; description: string; }
export interface EditorPhase {
  number: number; title: string; status: string;
  content: string; verification: string[]; files: string[];
  addressesCriteria: string[]; dependencies: number[];
  startedAt?: string | null; completedAt?: string | null; summary?: string | null;
