### Extract SortablePhaseCard

Move the per-phase card UI (from Phase 3) into a `SortablePhaseCard` sub-component that calls `useSortable({ id: phase.number })`. Apply `transform`/`transition`/`opacity` styles. Render a drag handle div with `{...attributes} {...listeners}` (use a unicode dot icon like `⋮⋮`).

### Wire DndContext

```ts
const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 6 } }));
function handleDragEnd(event: DragEndEvent) {
  const { active, over } = event;
  if (over && active.id !== over.id) {
    setDraft(d => {
      const oldIdx = d.phases.findIndex(p => p.number === active.id);
      const newIdx = d.phases.findIndex(p => p.number === over.id);
      return { ...d, phases: arrayMove(d.phases, oldIdx, newIdx) };
    });
  }
}
```

Wrap phase list in `<DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}><SortableContext items={draft.phases.map(p => p.number)} strategy={verticalListSortingStrategy}>...</SortableContext></DndContext>`.

