Pure derivation logic + lightweight validation surfacing inline.

### Coverage matrix

```ts
function recomputeCoverageMatrix(phases: EditorPhase[], criteria: EditorSuccessCriterion[]): Record<string, number[]> {
  const matrix: Record<string, number[]> = {};
  for (const sc of criteria) matrix[sc.id] = [];
  for (const phase of phases) {
    for (const scId of phase.addressesCriteria) {
      if (matrix[scId] !== undefined) matrix[scId].push(phase.number);
    }
  }
  return matrix;
}
```

Derive in `useMemo`: `const coverageMatrix = useMemo(() => recomputeCoverageMatrix(draft.phases, draft.successCriteria), [draft.phases, draft.successCriteria]);`

### Validation

```ts
interface ValidationError { field: string; message: string; }
function validateDraft(draft: EditorPlan): ValidationError[] {
  const errors: ValidationError[] = [];
  const phaseNumbers = new Set<number>();
  const knownScIds = new Set(draft.successCriteria.map(sc => sc.id));
  for (const phase of draft.phases) {
    if (!phase.title.trim()) errors.push({ field: `phase-${phase.number}-title`, message: 'Title is required' });
    if (phaseNumbers.has(phase.number)) errors.push({ field: `phase-${phase.number}-number`, message: `Duplicate phase number ${phase.number}` });
    phaseNumbers.add(phase.number);
  }
  for (const phase of draft.phases) {
    for (const dep of phase.dependencies) {
      if (!phaseNumbers.has(dep)) errors.push({ field: `phase-${phase.number}-deps`, message: `Dependency ${dep} does not reference a known phase` });
    }
    for (const scId of phase.addressesCriteria) {
      if (!knownScIds.has(scId)) errors.push({ field: `phase-${phase.number}-criteria`, message: `Criterion '${scId}' does not exist` });
    }
  }
  return errors;
}
const errors = useMemo(() => validateDraft(draft), [draft]);
```

