### Save handler

```ts
async function handleSave() {
  if (errors.length > 0) return;
  setIsSaving(true);
  setSaveError(null);
  try {
    const payload = { ...draft, coverageMatrix };
    await invoke('save_plan', {
      issueNumber,
      plan: payload,
      tikiPath: activeProject?.path ? `${activeProject.path}/.tiki` : undefined,
    });
    onClose(); // file watcher reloads plan
  } catch (e) {
    setSaveError(String(e));
  } finally { setIsSaving(false); }
}
```

Import `invoke` from `@tauri-apps/api/core` and `useProjectsStore` (or whatever exposes `activeProject`).

